/**
 * Table Management Module Types
 *
 * Type definitions for future table management module implementation.
 * This file defines interfaces for table CRUD, floor plan management,
 * and capacity planning.
 *
 * @module modules/_stubs/table-management/types
 *
 * @example
 * ```typescript
 * import type {
 *   ITableService,
 *   Table,
 *   FloorPlan,
 * } from '@/modules/_stubs/table-management';
 * ```
 */

// -----------------------------------------------------------------------------
// Enums
// -----------------------------------------------------------------------------

/**
 * Table status
 */
export enum TableStatus {
  /** Table is available */
  AVAILABLE = 'AVAILABLE',
  /** Table is occupied */
  OCCUPIED = 'OCCUPIED',
  /** Table is reserved */
  RESERVED = 'RESERVED',
  /** Table being cleaned */
  CLEANING = 'CLEANING',
  /** Table is blocked/unavailable */
  BLOCKED = 'BLOCKED',
}

/**
 * Table shape
 */
export enum TableShape {
  /** Square table */
  SQUARE = 'SQUARE',
  /** Round table */
  ROUND = 'ROUND',
  /** Rectangle table */
  RECTANGLE = 'RECTANGLE',
  /** Oval table */
  OVAL = 'OVAL',
  /** Bar seat */
  BAR = 'BAR',
  /** Booth */
  BOOTH = 'BOOTH',
  /** Custom shape */
  CUSTOM = 'CUSTOM',
}

/**
 * Section type
 */
export enum SectionType {
  /** Indoor section */
  INDOOR = 'INDOOR',
  /** Outdoor section */
  OUTDOOR = 'OUTDOOR',
  /** Terrace */
  TERRACE = 'TERRACE',
  /** VIP section */
  VIP = 'VIP',
  /** Bar area */
  BAR = 'BAR',
  /** Private room */
  PRIVATE = 'PRIVATE',
}

// -----------------------------------------------------------------------------
// Entity Types
// -----------------------------------------------------------------------------

/**
 * Table entity
 */
export interface Table {
  /** Table ID */
  id: string;
  /** Organization ID */
  organizationId: string;
  /** Branch ID */
  branchId: string;
  /** Section ID */
  sectionId: string | null;
  /** Table number */
  tableNumber: string;
  /** Display name */
  name: string | null;
  /** Status */
  status: TableStatus;
  /** Capacity (seats) */
  capacity: number;
  /** Minimum seats */
  minCapacity: number;
  /** Shape */
  shape: TableShape;
  /** Position X (for floor plan) */
  positionX: number | null;
  /** Position Y (for floor plan) */
  positionY: number | null;
  /** Width (for floor plan) */
  width: number | null;
  /** Height (for floor plan) */
  height: number | null;
  /** Rotation (degrees) */
  rotation: number;
  /** QR code ID (if assigned) */
  qrCodeId: string | null;
  /** Current order ID */
  currentOrderId: string | null;
  /** Current reservation ID */
  currentReservationId: string | null;
  /** Occupied since */
  occupiedSince: Date | null;
  /** Is combinable (can merge with others) */
  isCombinable: boolean;
  /** Combined with table IDs */
  combinedWith: string[];
  /** Is active */
  isActive: boolean;
  /** Display order */
  displayOrder: number;
  /** Notes */
  notes: string | null;
  /** Created at */
  createdAt: Date;
  /** Updated at */
  updatedAt: Date;
}

/**
 * Section entity
 */
export interface Section {
  /** Section ID */
  id: string;
  /** Organization ID */
  organizationId: string;
  /** Branch ID */
  branchId: string;
  /** Floor plan ID */
  floorPlanId: string | null;
  /** Section name */
  name: string;
  /** Section type */
  type: SectionType;
  /** Description */
  description: string | null;
  /** Color for display */
  color: string;
  /** Total capacity */
  totalCapacity: number;
  /** Table count */
  tableCount: number;
  /** Is smoking allowed */
  smokingAllowed: boolean;
  /** Is active */
  isActive: boolean;
  /** Display order */
  displayOrder: number;
  /** Created at */
  createdAt: Date;
  /** Updated at */
  updatedAt: Date;
}

/**
 * Floor plan entity
 */
export interface FloorPlan {
  /** Floor plan ID */
  id: string;
  /** Organization ID */
  organizationId: string;
  /** Branch ID */
  branchId: string;
  /** Floor plan name */
  name: string;
  /** Description */
  description: string | null;
  /** Canvas width */
  width: number;
  /** Canvas height */
  height: number;
  /** Background image URL */
  backgroundImage: string | null;
  /** Is default floor plan */
  isDefault: boolean;
  /** Is active */
  isActive: boolean;
  /** Created at */
  createdAt: Date;
  /** Updated at */
  updatedAt: Date;
}

/**
 * Table history entry
 */
export interface TableHistoryEntry {
  /** Entry ID */
  id: string;
  /** Table ID */
  tableId: string;
  /** Previous status */
  previousStatus: TableStatus;
  /** New status */
  newStatus: TableStatus;
  /** Order ID (if applicable) */
  orderId: string | null;
  /** Reservation ID (if applicable) */
  reservationId: string | null;
  /** Party size */
  partySize: number | null;
  /** Duration (minutes) */
  durationMinutes: number | null;
  /** Changed by user ID */
  changedById: string | null;
  /** Created at */
  createdAt: Date;
}

// -----------------------------------------------------------------------------
// Request Types
// -----------------------------------------------------------------------------

/**
 * Create table request
 */
export interface CreateTableRequest {
  /** Branch ID */
  branchId: string;
  /** Section ID */
  sectionId?: string;
  /** Table number */
  tableNumber: string;
  /** Display name */
  name?: string;
  /** Capacity */
  capacity: number;
  /** Minimum capacity */
  minCapacity?: number;
  /** Shape */
  shape?: TableShape;
  /** Position X */
  positionX?: number;
  /** Position Y */
  positionY?: number;
  /** Width */
  width?: number;
  /** Height */
  height?: number;
  /** Is combinable */
  isCombinable?: boolean;
  /** Notes */
  notes?: string;
}

/**
 * Update table request
 */
export interface UpdateTableRequest {
  /** Section ID */
  sectionId?: string | null;
  /** Table number */
  tableNumber?: string;
  /** Display name */
  name?: string | null;
  /** Capacity */
  capacity?: number;
  /** Minimum capacity */
  minCapacity?: number;
  /** Shape */
  shape?: TableShape;
  /** Position X */
  positionX?: number;
  /** Position Y */
  positionY?: number;
  /** Width */
  width?: number;
  /** Height */
  height?: number;
  /** Rotation */
  rotation?: number;
  /** Is combinable */
  isCombinable?: boolean;
  /** Is active */
  isActive?: boolean;
  /** Notes */
  notes?: string;
}

/**
 * Change table status request
 */
export interface ChangeTableStatusRequest {
  /** Table ID */
  tableId: string;
  /** New status */
  status: TableStatus;
  /** Order ID (if occupying) */
  orderId?: string;
  /** Party size */
  partySize?: number;
}

/**
 * Create section request
 */
export interface CreateSectionRequest {
  /** Branch ID */
  branchId: string;
  /** Floor plan ID */
  floorPlanId?: string;
  /** Section name */
  name: string;
  /** Section type */
  type: SectionType;
  /** Description */
  description?: string;
  /** Color */
  color?: string;
  /** Smoking allowed */
  smokingAllowed?: boolean;
}

/**
 * Create floor plan request
 */
export interface CreateFloorPlanRequest {
  /** Branch ID */
  branchId: string;
  /** Floor plan name */
  name: string;
  /** Description */
  description?: string;
  /** Canvas width */
  width: number;
  /** Canvas height */
  height: number;
  /** Background image URL */
  backgroundImage?: string;
  /** Is default */
  isDefault?: boolean;
}

/**
 * Combine tables request
 */
export interface CombineTablesRequest {
  /** Primary table ID */
  primaryTableId: string;
  /** Table IDs to combine */
  tableIds: string[];
}

// -----------------------------------------------------------------------------
// Response Types
// -----------------------------------------------------------------------------

/**
 * Table availability
 */
export interface TableAvailability {
  /** Table ID */
  tableId: string;
  /** Table number */
  tableNumber: string;
  /** Is available */
  isAvailable: boolean;
  /** Current status */
  status: TableStatus;
  /** Capacity */
  capacity: number;
  /** Estimated available at */
  estimatedAvailableAt: Date | null;
}

/**
 * Section summary
 */
export interface SectionSummary {
  /** Section ID */
  sectionId: string;
  /** Section name */
  name: string;
  /** Type */
  type: SectionType;
  /** Total tables */
  totalTables: number;
  /** Available tables */
  availableTables: number;
  /** Occupied tables */
  occupiedTables: number;
  /** Reserved tables */
  reservedTables: number;
  /** Total capacity */
  totalCapacity: number;
  /** Current guests */
  currentGuests: number;
}

/**
 * Floor plan with tables
 */
export interface FloorPlanWithTables {
  /** Floor plan */
  floorPlan: FloorPlan;
  /** Sections */
  sections: Section[];
  /** Tables */
  tables: Table[];
}

/**
 * Table turnover stats
 */
export interface TableTurnoverStats {
  /** Table ID */
  tableId: string;
  /** Table number */
  tableNumber: string;
  /** Average turnover time (minutes) */
  avgTurnoverMinutes: number;
  /** Total seatings today */
  seatingsToday: number;
  /** Total revenue today */
  revenueToday: number;
}

// -----------------------------------------------------------------------------
// Service Interfaces
// -----------------------------------------------------------------------------

/**
 * Table service interface
 */
export interface ITableService {
  /**
   * Create table
   */
  createTable(
    organizationId: string,
    request: CreateTableRequest
  ): Promise<Table>;

  /**
   * Get table by ID
   */
  getTable(
    organizationId: string,
    tableId: string
  ): Promise<Table>;

  /**
   * Get table by number
   */
  getTableByNumber(
    organizationId: string,
    branchId: string,
    tableNumber: string
  ): Promise<Table>;

  /**
   * List tables
   */
  listTables(
    organizationId: string,
    branchId: string,
    sectionId?: string
  ): Promise<Table[]>;

  /**
   * Update table
   */
  updateTable(
    organizationId: string,
    tableId: string,
    request: UpdateTableRequest
  ): Promise<Table>;

  /**
   * Delete table
   */
  deleteTable(
    organizationId: string,
    tableId: string
  ): Promise<void>;

  /**
   * Change table status
   */
  changeStatus(
    organizationId: string,
    request: ChangeTableStatusRequest
  ): Promise<Table>;

  /**
   * Get available tables
   */
  getAvailableTables(
    organizationId: string,
    branchId: string,
    partySize: number
  ): Promise<TableAvailability[]>;

  /**
   * Combine tables
   */
  combineTables(
    organizationId: string,
    request: CombineTablesRequest
  ): Promise<Table>;

  /**
   * Split combined tables
   */
  splitTables(
    organizationId: string,
    tableId: string
  ): Promise<Table[]>;

  /**
   * Get table history
   */
  getTableHistory(
    organizationId: string,
    tableId: string,
    limit?: number
  ): Promise<TableHistoryEntry[]>;

  /**
   * Get turnover stats
   */
  getTurnoverStats(
    organizationId: string,
    branchId: string,
    date?: string
  ): Promise<TableTurnoverStats[]>;
}

/**
 * Floor plan service interface
 */
export interface IFloorPlanService {
  /**
   * Create floor plan
   */
  createFloorPlan(
    organizationId: string,
    request: CreateFloorPlanRequest
  ): Promise<FloorPlan>;

  /**
   * Get floor plan by ID
   */
  getFloorPlan(
    organizationId: string,
    floorPlanId: string
  ): Promise<FloorPlan>;

  /**
   * Get floor plan with tables
   */
  getFloorPlanWithTables(
    organizationId: string,
    floorPlanId: string
  ): Promise<FloorPlanWithTables>;

  /**
   * List floor plans
   */
  listFloorPlans(
    organizationId: string,
    branchId: string
  ): Promise<FloorPlan[]>;

  /**
   * Update floor plan
   */
  updateFloorPlan(
    organizationId: string,
    floorPlanId: string,
    updates: Partial<CreateFloorPlanRequest>
  ): Promise<FloorPlan>;

  /**
   * Delete floor plan
   */
  deleteFloorPlan(
    organizationId: string,
    floorPlanId: string
  ): Promise<void>;

  /**
   * Set default floor plan
   */
  setDefaultFloorPlan(
    organizationId: string,
    branchId: string,
    floorPlanId: string
  ): Promise<FloorPlan>;

  /**
   * Create section
   */
  createSection(
    organizationId: string,
    request: CreateSectionRequest
  ): Promise<Section>;

  /**
   * List sections
   */
  listSections(
    organizationId: string,
    branchId: string
  ): Promise<Section[]>;

  /**
   * Get section summary
   */
  getSectionSummary(
    organizationId: string,
    branchId: string
  ): Promise<SectionSummary[]>;

  /**
   * Update section
   */
  updateSection(
    organizationId: string,
    sectionId: string,
    updates: Partial<CreateSectionRequest>
  ): Promise<Section>;

  /**
   * Delete section
   */
  deleteSection(
    organizationId: string,
    sectionId: string
  ): Promise<void>;
}

// -----------------------------------------------------------------------------
// Event Payload Types
// -----------------------------------------------------------------------------

/**
 * Table created event payload
 */
export interface TableCreatedEventPayload {
  organizationId: string;
  branchId: string;
  tableId: string;
  tableNumber: string;
  capacity: number;
  sectionId: string | null;
  timestamp: string;
}

/**
 * Table status changed event payload
 */
export interface TableStatusChangedEventPayload {
  organizationId: string;
  tableId: string;
  tableNumber: string;
  previousStatus: TableStatus;
  newStatus: TableStatus;
  orderId: string | null;
  partySize: number | null;
  timestamp: string;
}

/**
 * Table occupied event payload
 */
export interface TableOccupiedEventPayload {
  organizationId: string;
  tableId: string;
  tableNumber: string;
  orderId: string | null;
  partySize: number;
  timestamp: string;
}

/**
 * Table available event payload
 */
export interface TableAvailableEventPayload {
  organizationId: string;
  tableId: string;
  tableNumber: string;
  durationMinutes: number;
  timestamp: string;
}

/**
 * Floor plan updated event payload
 */
export interface FloorPlanUpdatedEventPayload {
  organizationId: string;
  branchId: string;
  floorPlanId: string;
  timestamp: string;
}
